<template>  <div class="menu-management">    <el-card>      <template #header>        <div class="card-header">          <span>菜单管理</span>          <el-button            v-if="authStore.hasPermission('menu:create')"            type="primary"            @click="showCreateDialog = true"          >            新增菜单          </el-button>        </div>      </template>      <!-- 搜索 -->      <div class="filter-section">        <el-input          v-model="searchKeyword"          placeholder="搜索菜单名称或路径"          style="width: 300px;"          clearable          @input="handleSearch"        />      </div>      <!-- 菜单列表 -->      <el-table        :data="filteredMenus"        style="width: 100%"        v-loading="loading"        row-key="id"        :tree-props="{children: 'children', hasChildren: 'hasChildren'}"      >        <el-table-column prop="id" label="ID" width="80" />        <el-table-column prop="name" label="菜单名称" width="150" />        <el-table-column prop="path" label="路径" min-width="150" />        <el-table-column prop="icon" label="图标" width="100" />        <el-table-column prop="order" label="排序" width="80" />        <el-table-column prop="createdAt" label="创建时间" width="180">          <template #default="scope">            {{ formatDate(scope.row.createdAt) }}          </template>        </el-table-column>        <el-table-column label="关联角色" min-width="200">          <template #default="scope">            <el-tag              v-for="role in scope.row.roles"              :key="role.id"              size="small"              style="margin: 2px;"            >              {{ role.name }}            </el-tag>          </template>        </el-table-column>        <el-table-column label="操作" width="200" fixed="right">          <template #default="scope">            <el-button              v-if="authStore.hasPermission('menu:update')"              type="primary"              size="small"              @click="editMenu(scope.row)"            >              编辑            </el-button>            <el-button              v-if="authStore.hasPermission('menu:create')"              type="success"              size="small"              @click="addChildMenu(scope.row)"              style="margin-left: 5px;"            >              添加子菜单            </el-button>            <el-button              v-if="authStore.hasPermission('menu:delete')"              type="danger"              size="small"              @click="deleteMenu(scope.row)"              style="margin-left: 5px;"            >              删除            </el-button>          </template>        </el-table-column>      </el-table>      <!-- 分页 -->      <div class="pagination">        <el-pagination          v-model:current-page="currentPage"          v-model:page-size="pageSize"          :page-sizes="[10, 20, 50, 100]"          :total="totalMenus"          layout="total, sizes, prev, pager, next, jumper"          @size-change="handleSizeChange"          @current-change="handleCurrentChange"        />      </div>    </el-card>    <!-- 新增/编辑菜单对话框 -->    <el-dialog      v-model="showCreateDialog"      :title="isEditing ? '编辑菜单' : '新增菜单'"      width="600px"    >      <el-form        ref="menuFormRef"        :model="menuForm"        :rules="menuRules"        label-width="100px"      >        <el-form-item label="菜单名称" prop="name">          <el-input            v-model="menuForm.name"            placeholder="请输入菜单名称"          />        </el-form-item>        <el-form-item label="路径" prop="path">          <el-input            v-model="menuForm.path"            placeholder="请输入路由路径，如 /admin/users"          />        </el-form-item>        <el-form-item label="图标" prop="icon">          <el-input            v-model="menuForm.icon"            placeholder="请输入图标名称，如 user 或 menu"          />        </el-form-item>        <el-form-item label="组件" prop="component">          <el-input            v-model="menuForm.component"            placeholder="请输入组件名称，如 UserList"          />        </el-form-item>        <el-form-item label="父菜单" prop="parentId">          <el-select            v-model="menuForm.parentId"            placeholder="选择父菜单（可选）"            style="width: 100%"            clearable          >            <el-option              v-for="menu in allMenus.filter(m => !m.parentId)"              :key="menu.id"              :label="menu.name"              :value="menu.id"            />          </el-select>        </el-form-item>        <el-form-item label="排序" prop="order">          <el-input-number            v-model="menuForm.order"            :min="0"            :max="999"            placeholder="请输入排序号"          />        </el-form-item>        <el-form-item label="关联角色" prop="roleIds">          <el-select            v-model="menuForm.roleIds"            multiple            placeholder="选择可以访问此菜单的角色"            style="width: 100%"            filterable          >            <el-option              v-for="role in allRoles"              :key="role.id"              :label="role.name"              :value="role.id"            />          </el-select>        </el-form-item>      </el-form>      <template #footer>        <span class="dialog-footer">          <el-button @click="showCreateDialog = false">取消</el-button>          <el-button            type="primary"            :loading="submitLoading"            @click="handleSubmit"          >            {{ isEditing ? '更新' : '创建' }}          </el-button>        </span>      </template>    </el-dialog>  </div></template><script>import { ref, reactive, onMounted, computed } from 'vue'import { useAuthStore } from '../stores/auth'import axios from 'axios'import { ElMessage, ElMessageBox } from 'element-plus'export default {  name: 'MenuManagementView',  setup() {    const authStore = useAuthStore()    const menus = ref([])    const allMenus = ref([])    const allRoles = ref([])    const loading = ref(false)    const submitLoading = ref(false)    const showCreateDialog = ref(false)    const isEditing = ref(false)    const searchKeyword = ref('')    const currentPage = ref(1)    const pageSize = ref(10)    const totalMenus = ref(0)    const menuFormRef = ref()    const menuForm = reactive({      id: null,      name: '',      path: '',      icon: '',      component: '',      parentId: null,      order: 0,      roleIds: []    })    const menuRules = {      name: [        { required: true, message: '请输入菜单名称', trigger: 'blur' },        { min: 1, max: 50, message: '菜单名称长度在 1 到 50 个字符', trigger: 'blur' }      ],      path: [        { pattern: /^\/.*$/, message: '路径必须以 / 开头', trigger: 'blur' }      ],      order: [        { type: 'number', min: 0, max: 999, message: '排序号必须在 0-999 之间', trigger: 'blur' }      ]    }    // 计算过滤后的菜单列表    const filteredMenus = computed(() => {      let filtered = [...allMenus.value]      // 搜索      if (searchKeyword.value) {        const keyword = searchKeyword.value.toLowerCase()        filtered = filtered.filter(menu =>            menu.name.toLowerCase().includes(keyword) ||            (menu.path && menu.path.toLowerCase().includes(keyword))        )      }      // 构建树      const menuMap = new Map()      const roots = []      filtered.forEach(menu => {        menuMap.set(menu.id, { ...menu, children: [] })      })      filtered.forEach(menu => {        if (menu.parentId && menuMap.has(menu.parentId)) {          menuMap.get(menu.parentId).children.push(menuMap.get(menu.id))        } else if (!menu.parentId) {          roots.push(menuMap.get(menu.id))        }      })      // 排序      const sortMenus = (menus) => {        menus.sort((a, b) => a.order - b.order)        menus.forEach(menu => {          if (menu.children?.length) {            sortMenus(menu.children)          }        })        return menus      }      return sortMenus(roots)    })    const fetchMenus = async () => {      if (!authStore.hasPermission('menu:list')) return      loading.value = true      try {        const response = await axios.get('http://localhost:3000/api/menus', {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          allMenus.value = response.data.data        }      } catch (error) {        console.error('Fetch menus error:', error)        ElMessage.error('获取菜单列表失败')      } finally {        loading.value = false      }    }    const fetchRoles = async () => {      if (!authStore.hasPermission('role:list')) return      try {        const response = await axios.get('http://localhost:3000/api/roles', {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          allRoles.value = response.data.data        }      } catch (error) {        console.error('Fetch roles error:', error)      }    }    const handleSearch = () => {      currentPage.value = 1    }    const handleSizeChange = (val) => {      pageSize.value = val      currentPage.value = 1    }    const handleCurrentChange = (val) => {      currentPage.value = val    }    const resetForm = () => {      menuForm.id = null      menuForm.name = ''      menuForm.path = ''      menuForm.icon = ''      menuForm.component = ''      menuForm.parentId = null      menuForm.order = 0      menuForm.roleIds = []    }    const editMenu = (menu) => {      isEditing.value = true      menuForm.id = menu.id      menuForm.name = menu.name      menuForm.path = menu.path || ''      menuForm.icon = menu.icon || ''      menuForm.component = menu.component || ''      menuForm.parentId = menu.parentId || null      menuForm.order = menu.order || 0      menuForm.roleIds = menu.roles ? menu.roles.map(r => r.id) : []      showCreateDialog.value = true    }    const addChildMenu = (parentMenu) => {      isEditing.value = false      resetForm()      menuForm.parentId = parentMenu.id      menuForm.order = (parentMenu.children?.length || 0) + 1      showCreateDialog.value = true    }    const deleteMenu = async (menu) => {      try {        await ElMessageBox.confirm(          `确定要删除菜单 "${menu.name}" 吗？此操作不可恢复。`,          '确认删除',          {            confirmButtonText: '确定',            cancelButtonText: '取消',            type: 'warning',          }        )        const response = await axios.delete(`http://localhost:3000/api/menus/${menu.id}`, {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          ElMessage.success('删除成功')          fetchMenus()        }      } catch (error) {        if (error !== 'cancel') {          console.error('Delete menu error:', error)          ElMessage.error('删除失败')        }      }    }    const handleSubmit = async () => {      try {        await menuFormRef.value.validate()        submitLoading.value = true        const formData = {          name: menuForm.name,          path: menuForm.path || undefined,          icon: menuForm.icon || undefined,          component: menuForm.component || undefined,          parentId: menuForm.parentId || undefined,          order: menuForm.order || 0        }        let response        if (isEditing.value) {          if (!authStore.hasPermission('menu:update')) {            ElMessage.error('没有编辑权限')            return          }          response = await axios.put(`http://localhost:3000/api/menus/${menuForm.id}`, formData, {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          })        } else {          if (!authStore.hasPermission('menu:create')) {            ElMessage.error('没有创建权限')            return          }          response = await axios.post('http://localhost:3000/api/menus', formData, {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          })        }        if (response.data.success) {          ElMessage.success(isEditing.value ? '更新成功' : '创建成功')          showCreateDialog.value = false          resetForm()          fetchMenus()        }      } catch (error) {        console.error('Submit menu error:', error)        ElMessage.error(error.response?.data?.message || '操作失败')      } finally {        submitLoading.value = false      }    }    const formatDate = (dateString) => {      return new Date(dateString).toLocaleString('zh-CN')    }    onMounted(() => {      fetchMenus()      fetchRoles()    })    return {      authStore,      menus,      allMenus,      allRoles,      loading,      submitLoading,      showCreateDialog,      isEditing,      searchKeyword,      currentPage,      pageSize,      totalMenus,      filteredMenus,      menuFormRef,      menuForm,      menuRules,      handleSearch,      handleSizeChange,      handleCurrentChange,      editMenu,      addChildMenu,      deleteMenu,      handleSubmit,      formatDate    }  }}</script><style scoped>.menu-management {  padding: 20px;}.card-header {  display: flex;  justify-content: space-between;  align-items: center;}.filter-section {  margin-bottom: 20px;}.pagination {  margin-top: 20px;  text-align: right;}.dialog-footer {  text-align: right;}</style>